;(function(){const loadingStatesUndoQueue=[];function loadingStateContainer(t){return htmx.closest(t,'[data-loading-states]')||document.body}function mayProcessUndoCallback(t,cb){if(document.body.contains(t))cb()}function mayProcessLoadingStateByPath(e,p){const pe=htmx.closest(e,'[data-loading-path]');return pe?pe.getAttribute('data-loading-path')===p:true}function queueLoadingState(se,te,doFn,undoFn){const de=htmx.closest(se,'[data-loading-delay]');if(de){const d=de.getAttribute('data-loading-delay')||200,t=setTimeout(function(){doFn();loadingStatesUndoQueue.push(function(){mayProcessUndoCallback(te,undoFn)})},d);loadingStatesUndoQueue.push(function(){mayProcessUndoCallback(te,function(){clearTimeout(t)})})}else{doFn();loadingStatesUndoQueue.push(function(){mayProcessUndoCallback(te,undoFn)})}}function getLoadingStateElts(s,t,p){return Array.from(htmx.findAll(s,'['+t+']')).filter(function(e){return mayProcessLoadingStateByPath(e,p)})}function getLoadingTarget(e){if(e.getAttribute('data-loading-target'))return Array.from(htmx.findAll(e.getAttribute('data-loading-target')));return[e]}htmx.defineExtension('loading-states',{onEvent:function(name,evt){if(name==='htmx:beforeRequest'){const c=loadingStateContainer(evt.target),types=['data-loading','data-loading-class','data-loading-class-remove','data-loading-disable','data-loading-aria-busy'],elts={};types.forEach(function(t){elts[t]=getLoadingStateElts(c,t,evt.detail.pathInfo.requestPath)});elts['data-loading'].forEach(function(se){getLoadingTarget(se).forEach(function(te){queueLoadingState(se,te,function(){te.style.display=se.getAttribute('data-loading')||'inline-block'},function(){te.style.display='none'})})});elts['data-loading-class'].forEach(function(se){const cn=se.getAttribute('data-loading-class').split(' ');getLoadingTarget(se).forEach(function(te){queueLoadingState(se,te,function(){cn.forEach(function(c){te.classList.add(c)})},function(){cn.forEach(function(c){te.classList.remove(c)})})})});elts['data-loading-class-remove'].forEach(function(se){const cn=se.getAttribute('data-loading-class-remove').split(' ');getLoadingTarget(se).forEach(function(te){queueLoadingState(se,te,function(){cn.forEach(function(c){te.classList.remove(c)})},function(){cn.forEach(function(c){te.classList.add(c)})})})});elts['data-loading-disable'].forEach(function(se){getLoadingTarget(se).forEach(function(te){queueLoadingState(se,te,function(){te.disabled=true},function(){te.disabled=false})})});elts['data-loading-aria-busy'].forEach(function(se){getLoadingTarget(se).forEach(function(te){queueLoadingState(se,te,function(){te.setAttribute('aria-busy','true')},function(){te.removeAttribute('aria-busy')})})})}if(name==='htmx:beforeOnLoad'){while(loadingStatesUndoQueue.length>0)loadingStatesUndoQueue.shift()()}}})})();
(function(){var api,attrPrefix='hx-target-';function startsWith(s,p){return s.substring(0,p.length)===p}function getRespCodeTarget(e,n){if(!e||!n)return null;var r=n.toString(),ap=[r,r.substr(0,2)+'*',r.substr(0,2)+'x',r.substr(0,1)+'*',r.substr(0,1)+'x',r.substr(0,1)+'**',r.substr(0,1)+'xx','*','x','***','xxx'];if(startsWith(r,'4')||startsWith(r,'5'))ap.push('error');for(var i=0;i<ap.length;i++){var a=attrPrefix+ap[i],v=api.getClosestAttributeValue(e,a);if(v){return v==='this'?api.findThisElement(e,a):api.querySelectorExt(e,v)}}return null}function handleErrorFlag(evt){if(evt.detail.isError){if(htmx.config.responseTargetUnsetsError)evt.detail.isError=false}else if(htmx.config.responseTargetSetsError)evt.detail.isError=true}htmx.defineExtension('response-targets',{init:function(apiRef){api=apiRef;if(htmx.config.responseTargetUnsetsError===undefined)htmx.config.responseTargetUnsetsError=true;if(htmx.config.responseTargetSetsError===undefined)htmx.config.responseTargetSetsError=false;if(htmx.config.responseTargetPrefersExisting===undefined)htmx.config.responseTargetPrefersExisting=false;if(htmx.config.responseTargetPrefersRetargetHeader===undefined)htmx.config.responseTargetPrefersRetargetHeader=true},onEvent:function(name,evt){if(name==='htmx:beforeSwap'&&evt.detail.xhr&&evt.detail.xhr.status!==200){if(evt.detail.target){if(htmx.config.responseTargetPrefersExisting){evt.detail.shouldSwap=true;handleErrorFlag(evt);return true}if(htmx.config.responseTargetPrefersRetargetHeader&&evt.detail.xhr.getAllResponseHeaders().match(/HX-Retarget:/i)){evt.detail.shouldSwap=true;handleErrorFlag(evt);return true}}if(!evt.detail.requestConfig)return true;var t=getRespCodeTarget(evt.detail.requestConfig.elt,evt.detail.xhr.status);if(t){handleErrorFlag(evt);evt.detail.shouldSwap=true;evt.detail.target=t}return true}}})})();
